CustomFunction.Calculation:
// Accepts a ¶-delimited list (e.g. from List() / GetFieldName()) or a
// comma-separated string. FileMaker fully-qualified names (Table::Field) are
// converted to quoted SQL dot notation ("Table"."Field"). Other expressions
// (*, COUNT(*), already-dotted names, etc.) pass through unchanged.
Let
(
[
_fqName = GetFieldName ( columns ) ;
_input = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; columns ) ;
_normalized = Substitute ( Substitute ( _input ; ", " ; "¶" ) ; "," ; "¶" ) ;
_columnCount = ValueCount ( _normalized ) ;
_selects = QueryBuildSelects_cf ( _normalized ; _columnCount ; 1 ) ;
_selectKeys = QueryBuildSelectKeys_cf ( _normalized ; _columnCount ; 1 ) ;
_q1 = JSONSetElement ( query ; "selects" ; _selects ; JSONString )
];
JSONSetElement ( _q1 ; "selectKeys" ; _selectKeys ; JSONString )
)
